challenges.solution:
function createCounter() {
  let count = 0;

  return {
    increment() {
      count++;
      return this;
    },
    decrement() {
      count--;
      return this;
    },
    getValue() {
      return count;
    },
    reset() {
      count = 0;
      return this;
    }
  };
}

